ntCfg['prompt_sales'])?></textarea></div><div><label>Prompt suporte tecnico</label><textarea class="sc-search" id="agentPromptTechnical"><?=sc_h($agentCfg['prompt_technical'])?></textarea></div><div><label>Prompt reagendar live</label><textarea class="sc-search" id="agentPromptReschedule"><?=sc_h($agentCfg['prompt_reschedule'])?></textarea></div><div><label>Prompt gerar certificado</label><textarea class="sc-search" id="agentPromptCertificate"><?=sc_h($agentCfg['prompt_certificate'])?></textarea></div><div><label>Prompt enviar grupo</label><textarea class="sc-search" id="agentPromptGroup"><?=sc_h($agentCfg['prompt_group'])?></textarea></div><div class="sc-var-box"><label>Variaveis do agente</label><div class="text-muted text-xs">Pesquise pelo nome do campo, selecione na lista e ajuste a frase identificadora se precisar.</div><datalist id="agentPayloadFields"></datalist><div id="agentVarRows"></div><button type="button" class="btn btn-ghost btn-sm" id="agentVarAdd">+ Adicionar variavel</button></div><div><label>Colunas CRM JSON</label><textarea class="sc-search" id="crmStagesJson"><?=sc_h(json_encode($crmStages,JSON_UNESCAPED_UNICODE|JSON_PRETTY_PRINT))?></textarea></div></div><button class="btn btn-primary" id="agentSave" style="margin-top:14px">Salvar agente</button></div></section>
