const SC={csrf:<?=json_encode($csrf)?>,view:<?=json_encode($view)?>,identity:<?=json_encode($identity,JSON_UNESCAPED_UNICODE)?>,conversation:<?=(int)$initialConversation?>,simConversation:0,lastAdmin:0,lastSim:0,filter:'open',soundEnabled:<?=$supportSoundEnabled?'true':'false'?>,adminUnread:<?=$counts['unread']?>,humanWaiting:<?=$humanWaitingCount?>,graph:<?=json_encode($graph,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES)?>,flowId:<?=(int)($activeFlow['id']??0)?>};
const SUPPORT_AVATAR_SRC=<?=json_encode($supportAvatarSrc,JSON_UNESCAPED_SLASHES)?>;
const CRM_STAGES=<?=json_encode($crmStages,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES)?>,AGENT_VARIABLES=<?=json_encode($agentVariableMap,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES)?>,AGENT_FIELD_OPTIONS=<?=json_encode($agentFieldOptions,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES)?>;let CRM_CONVERSATIONS=<?=json_encode($crmConversations,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES)?>;
const SUPPORT_ASSIGNEES=<?=json_encode($supportAssignees,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES)?>;
const SUPPORT_ANALYTICS=<?=json_encode($supportAnalytics,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES)?>;
const SUPPORT_FPS=<?=json_encode($supportFps,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES)?>;
let SC_CONTEXT=null;
function installSupportSidePanel(){const panel=document.querySelector('.sc-crm');if(!panel||panel.dataset.enhanced)return;panel.dataset.enhanced='1';panel.id='scCrmPanel';panel.innerHTML='<h3>Central do aluno</h3><div id="scStudentMeta" class="text-muted text-xs">Nenhuma conversa selecionada.</div><section class="sc-side-card"><h4>Atribuicao</h4><button type="button" class="btn btn-primary btn-sm" id="scClaim">Puxar para mim</button><div class="field"><label>Atribuir para</label><select id="scAssignSelect"><option value="">Selecione</option></select></div><button type="button" class="btn btn-ghost btn-sm" id="scAssignApply">Atribuir conversa</button></section><section class="sc-side-card"><h4>Variaveis uteis</h4><div id="scContextVars" class="sc-context-vars"><span class="text-muted text-xs">Abra uma conversa para carregar os dados.</span></div></section><section class="sc-side-card"><h4>Acoes do atendimento</h4><div class="sc-action-grid"><button type="button" id="scSendLogin">Enviar login direto</button><button type="button" id="scSendGroup">Enviar link do grupo</button><button type="button" id="scSendCertificate">Enviar certificado</button><button type="button" id="scGenerateCertificate">Gerar certificado</button></div><div class="field"><label>Reagendar live</label><select id="scRescheduleSlot"><option value="">Selecione uma data</option></select></div><button type="button" class="btn btn-ghost btn-sm" id="scRescheduleApply">Confirmar reagendamento</button><div class="sc-action-links"><a id="scEditStudent" target="_blank" rel="noopener">Ajustar dados do aluno</a><a id="scOpenStudentLogin" target="_blank" rel="noopener">Abrir como aluno</a></div></section><section class="sc-side-card"><h4>CRM</h4><div class="field"><label>Responsavel</label><input id="crmAssigned" placeholder="Nome do atendente"></div><div class="field"><label>Etapa</label><select id="crmStage"><option value="novo">Novo</option><option value="triagem">Triagem</option><option value="em_atendimento">Em atendimento</option><option value="aguardando_aluno">Aguardando aluno</option><option value="resolvido">Resolvido</option><option value="done">Concluido</option></select></div><div class="field"><label>Prioridade</label><select id="crmPriority"><option value="low">Baixa</option><option value="normal">Normal</option><option value="high">Alta</option><option value="urgent">Urgente</option></select></div><div class="field"><label>Status</label><select id="crmStatus"><option value="open">Aberto</option><option value="pending">Pendente</option><option value="closed">Resolvido</option></select></div><div class="field"><label>Tags</label><input id="crmTags" placeholder="Separadas por virgula"></div><div class="field"><label>Notas internas</label><textarea id="crmNotes" placeholder="Visivel apenas para a equipe"></textarea></div><button class="btn sc-save" id="crmSave">Salvar atendimento</button></section>'}
installSupportSidePanel();
const esc=s=>String(s??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));
function initSupportAnalytics(){if(!window.Chart||!document.getElementById('scClicksChart'))return;const A=SUPPORT_ANALYTICS,ticks='#94a3b8',grid='rgba(148,163,184,.12)',colors=['#22c55e','#38bdf8','#facc15','#fb7185','#a78bfa','#14b8a6','#f97316','#64748b'];const base={responsive:true,maintainAspectRatio:false,plugins:{legend:{labels:{color:ticks,boxWidth:11,font:{size:11}}}},scales:{x:{ticks:{color:ticks},grid:{color:grid}},y:{beginAtZero:true,ticks:{color:ticks,precision:0},grid:{color:grid}}}};const byLabel=(rows,key='total')=>({labels:rows.map(r=>r.label||r.k),data:rows.map(r=>+r[key]||0)});let c=byLabel(A.clicks);new Chart(scClicksChart,{type:'line',data:{labels:c.labels,datasets:[{label:'Cliques',data:c.data,borderColor:'#22c55e',backgroundColor:'rgba(34,197,94,.16)',fill:true,tension:.32,pointRadius:3}]},options:base});const labels=Array.from(new Set([...(A.started||[]).map(r=>r.label),...(A.closed||[]).map(r=>r.label)]));const val=(rows,label,key)=>+((rows||[]).find(r=>r.label===label)?.[key]||0);new Chart(scFlowChart,{type:'bar',data:{labels,datasets:[{label:'Iniciados',data:labels.map(l=>val(A.started,l,'total')),backgroundColor:'#38bdf8'},{label:'Concluídos humano',data:labels.map(l=>val(A.closed,l,'closed_human')),backgroundColor:'#22c55e'},{label:'Concluídos IA',data:labels.map(l=>val(A.closed,l,'closed_ai')),backgroundColor:'#a78bfa'}]},options:base});new Chart(scStatusChart,{type:'doughnut',data:{labels:(A.status||[]).map(r=>r.label||'status'),datasets:[{data:(A.status||[]).map(r=>+r.total||0),backgroundColor:colors}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'bottom',labels:{color:ticks,boxWidth:11,font:{size:11}}}}}});const agentLabels=Array.from(new Set((A.agents||[]).map(r=>r.label)));const agents=Array.from(new Set((A.agents||[]).map(r=>r.agent))).slice(0,6);const datasets=[];agents.forEach((agent,i)=>{datasets.push({type:'bar',label:agent+' iniciadas',data:agentLabels.map(l=>+((A.agents||[]).find(r=>r.agent===agent&&r.label===l)?.started||0)),backgroundColor:colors[i%colors.length]+'99'});datasets.push({type:'line',label:agent+' concluídas',data:agentLabels.map(l=>+((A.agents||[]).find(r=>r.agent===agent&&r.label===l)?.closed_total||0)),borderColor:colors[i%colors.length],backgroundColor:colors[i%colors.length],tension:.3,pointRadius:2})});new Chart(scAgentsChart,{data:{labels:agentLabels,datasets},options:base});new Chart(scTurmasChart,{type:'bar',data:{labels:(A.turmas||[]).map(r=>r.turma),datasets:[{label:'Atendimentos',data:(A.turmas||[]).map(r=>+r.total||0),backgroundColor:'#facc15'}]},options:{...base,indexAxis:'y'}});new Chart(scActionsChart,{type:'bar',data:{labels:(A.actions||[]).map(r=>r.label),datasets:[{label:'Ações',data:(A.actions||[]).map(r=>+r.total||0),backgroundColor:'#14b8a6'}]},options:{...base,indexAxis:'y'}})}
function initSupportFps(){if(!window.Chart||!document.getElementById('scFpsTrendChart')||window.__fpsChartsReady)return;window.__fpsChartsReady=true;const F=SUPPORT_FPS,ticks='#94a3b8',grid='rgba(148,163,184,.12)',base={responsive:true,maintainAspectRatio:false,plugins:{legend:{labels:{color:ticks,boxWidth:11,font:{size:11}}}},scales:{x:{ticks:{color:ticks},grid:{color:grid}},y:{beginAtZero:true,ticks:{color:ticks},grid:{color:grid}}}};new Chart(scFpsTrendChart,{type:'bar',data:{labels:(F.trend||[]).map(r=>r.label),datasets:[{label:'Respostas',data:(F.trend||[]).map(r=>+r.total||0),backgroundColor:'#38bdf8'},{type:'line',label:'Nota media',data:(F.trend||[]).map(r=>+r.avg_rating||0),borderColor:'#22c55e',backgroundColor:'#22c55e',tension:.3,yAxisID:'y1'}]},options:{...base,scales:{...base.scales,y1:{position:'right',min:0,max:5,ticks:{color:ticks},grid:{drawOnChartArea:false}}}}});const map=new Map((F.distribution||[]).map(r=>[String(r.label),+r.total||0]));new Chart(scFpsDistributionChart,{type:'doughnut',data:{labels:['0','1','2','3','4','5'].map(x=>x+' estrela(s)'),datasets:[{data:['0','1','2','3','4','5'].map(x=>map.get(x)||0),backgroundColor:['#64748b','#ef4444','#f97316','#facc15','#38bdf8','#22c55e']}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'bottom',labels:{color:ticks,boxWidth:11,font:{size:11}}}}}})}
async function analyzeSupportFps(){const el=document.getElementById('fpsReport');if(!el)return;el.textContent='Analisando respostas do filtro...';try{const q=new URLSearchParams({api:'fps_analysis',date_from:SUPPORT_FPS.from,date_to:SUPPORT_FPS.to,bucket:SUPPORT_FPS.bucket,turma:SUPPORT_FPS.turma||''});const j=await api('suporte_chat.php?'+q.toString());el.textContent=j.report||'Sem relatorio.'}catch(err){el.textContent=err.message}}
async function api(url,opt={}){const r=await fetch(url,opt),j=await r.json();if(!j.ok)throw new Error(j.error||'Falha na operação');return j}function post(action,data={},file=null){const f=new FormData();f.append('csrf',SC.csrf);f.append('action',action);Object.entries(data).forEach(([k,v])=>f.append(k,v));if(file)f.append('attachment',file);return api('suporte_chat.php',{method:'POST',body:f})}
function supportPayloadValue(path){let v=SC_CONTEXT?.payload;for(const part of String(path||'').split('.')){if(!part)continue;if(v&&typeof v==='object'&&part in v)v=v[part];else return ''}return v}
function displayValue(v){if(v===true)return 'Sim';if(v===false)return 'Nao';if(v==null||v==='')return '-';if(Array.isArray(v))return v.length?`${v.length} item(ns)`:'-';if(typeof v==='object')return Object.entries(v).slice(0,4).map(([k,val])=>`${k}: ${typeof val==='object'?'...':val}`).join(' | ');return String(v)}
function fillSupportMessage(text){if(!SC.conversation||!text)return;scText.value=text;scText.focus()}
async function quickSendSupport(text){fillSupportMessage(text);if(scCompose.requestSubmit)scCompose.requestSubmit();else scCompose.dispatchEvent(new Event('submit',{cancelable:true,bubbles:true}))}
async function loadSupportContext(){if(!SC.conversation)return;try{const j=await api(`suporte_chat.php?api=context&conversation_id=${SC.conversation}`);SC_CONTEXT=j;renderSupportContext(j)}catch(err){console.warn(err);scContextVars.innerHTML='<span class="text-muted text-xs">Nao foi possivel carregar os dados do aluno.</span>'}}
function renderSupportContext(j){const p=j.payload||{},a=p.aluno||{},links=p.links||{},cert=p.certificado||{},course=p.curso||{},vars=[['Nome',a.nome],['Email',a.email],['Telefone',a.telefone],['Turma',a.codigo_turma],['Data da live',a.data_live],['Aulas concluidas',(course.aulas_concluidas??0)+'/'+(course.aulas_obrigatorias??0)],['Avanco',(course.percentual_avanco??0)+'%'],['Certificado emitido',cert.tem_certificado_emitido?'Sim':'Nao'],['Link grupo',links.link_grupo_configurado],['Link certificado',cert.link_verificacao||cert.pdf_url||links.verificar_certificado_emitido],['Login direto',links.acesso_direto_area_membros]],history=(j.assignment_history||[]).map(h=>{let meta={};try{meta=JSON.parse(h.metadata_json||'{}')}catch(e){}return{at:h.created_at,actor:h.actor_name||'Sistema',to:meta.assigned_name||'-',from:meta.previous_assigned_name||'',reason:meta.reason||'atribuir'}});scContextVars.innerHTML=vars.map(([label,value])=>`<div class="sc-var-item"><span>${esc(label)}</span><b>${esc(displayValue(value))}</b></div>`).join('')+`<div class="sc-assignment-history"><h5>Histórico de atribuições</h5>${history.length?history.map(h=>`<div class="sc-assignment-item"><strong>${esc(h.to)}</strong><span>${fmtFull(h.at)} · atribuído por ${esc(h.actor)}</span>${h.from?`<em>Antes: ${esc(h.from)}</em>`:''}<small>${esc(h.reason==='mensagem_humana'?'Mensagem humana no chat':h.reason)}</small></div>`).join(''):'<p>Nenhuma atribuição registrada.</p>'}</div>`;scAssignSelect.innerHTML='<option value="">Selecione</option>'+(j.assignees||[]).map(x=>`<option value="${esc(x.name)}">${esc(x.name)}${x.email?' - '+esc(x.email):''}</option>`).join('');if(j.conversation?.assigned_name)scAssignSelect.value=j.conversation.assigned_name;scRescheduleSlot.innerHTML='<option value="">Selecione uma data</option>'+((p.reagendamento?.opcoes)||[]).map(x=>`<option value="${esc(x.iso)}">${esc(x.label)}</option>`).join('');scEditStudent.href='aluno_editar.php?id='+encodeURIComponent(a.id||'');scOpenStudentLogin.href=links.acesso_direto_area_membros||links.area_do_aluno||'#';updateSupportHeaderStatus(j.conversation);bindSupportHeaderActions()}
async function assignSupport(mode,name=''){if(!SC.conversation)return alert('Selecione uma conversa.');const j=await post('assign',{conversation_id:SC.conversation,mode,assigned_name:name});crmAssigned.value=j.assigned_name;await refreshAdmin(true);await loadSupportContext();await loadConversations();renderCrmBoard()}
function groupLinkFromContext(){const links=SC_CONTEXT?.payload?.links||{};return links.link_grupo_configurado||links.grupos_whatsapp?.[0]?.invite_url||links.grupos_whatsapp?.[0]?.public_url||''}
function certificateLinkFromContext(){const c=SC_CONTEXT?.payload?.certificado||{},l=SC_CONTEXT?.payload?.links||{};return c.pdf_url||c.link_verificacao||l.pdf_certificado_emitido||l.verificar_certificado_emitido||c.link_emitir||l.emitir_certificado||''}
function setSupportView(view){SC.view=view;document.querySelectorAll('.sc-view').forEach(x=>{const active=x.id==='view-'+view;x.classList.toggle('active',active);if(active)x.removeAttribute('hidden');else x.setAttribute('hidden','')});document.querySelectorAll('.sc-tab').forEach(x=>x.classList.toggle('active',(x.getAttribute('href')||'').includes('view='+view)));if(view==='crm')renderCrmBoard();if(view==='overview')initSupportAnalytics();if(view==='fps')initSupportFps()}
function crmMatch(c,cond){cond=String(cond||'').trim();if(!cond)return true;const [k,v]=cond.split('=').map(x=>x.trim());return String(c[k]??'')===v}
function crmApplyCondition(c,stage){c.stage=stage.id||c.stage||'agent';c.status=stage.id==='done'?'closed':(stage.id==='human'?'pending':'open');String(stage.condition||'').split(/[,&;]/).forEach(part=>{const [k,v]=part.split('=').map(x=>String(x||'').trim());if(k&&v)c[k]=v})}
function crmSummary(c){const notes=String(c.notes||'').split('\n').reverse().find(x=>x.includes('Agente transferiu para humano:'));if(notes)return notes.replace('Agente transferiu para humano:','').trim().slice(0,150);return String(c.last_body||'Atendimento iniciado').slice(0,150)}
function bindCrmBoard(){let dragging=null,dragMoved=false;document.querySelectorAll('.sc-card').forEach(card=>{card.ondragstart=e=>{dragging=card.dataset.id;dragMoved=false;e.dataTransfer.setData('text/plain',dragging);card.classList.add('dragging');e.dataTransfer.effectAllowed='move'};card.ondragend=()=>{card.classList.remove('dragging');document.querySelectorAll('.sc-col').forEach(c=>c.classList.remove('drag-over'));setTimeout(()=>{dragging=null;dragMoved=false},0)};card.onclick=()=>{if(dragMoved)return;const id=+card.dataset.id;setSupportView('live');history.replaceState(null,'','suporte_chat.php?view=live&conversation_id='+id);selectConversation(id)}});document.querySelectorAll('.sc-col').forEach(col=>{col.ondragover=e=>{e.preventDefault();dragMoved=true;col.classList.add('drag-over')};col.ondragleave=()=>col.classList.remove('drag-over');col.ondrop=async e=>{e.preventDefault();dragMoved=true;col.classList.remove('drag-over');const id=+(dragging||e.dataTransfer.getData('text/plain'));const stage=CRM_STAGES.find(s=>String(s.id)===col.dataset.stage);const conv=CRM_CONVERSATIONS.find(c=>+c.id===id);if(!stage||!conv)return;crmApplyCondition(conv,stage);renderCrmBoard();try{await post('move_crm',{conversation_id:id,stage_id:stage.id,condition:stage.condition||''});loadConversations()}catch(err){alert(err.message);location.reload()}}})}
function renderCrmBoard(){if(SC.view!=='crm')return;const el=document.querySelector('#view-crm .sc-panel');if(!el)return;el.innerHTML='<h2>CRM de suporte</h2><p class="text-muted text-sm">Arraste os cards entre as colunas. O resumo mostra o assunto e, quando houver, o motivo da transferencia para humano.</p><div class="sc-kanban">'+CRM_STAGES.map(s=>{const items=CRM_CONVERSATIONS.filter(c=>crmMatch(c,s.condition));return `<section class="sc-col" data-stage="${esc(s.id)}"><h3>${esc(s.label)} <span>${items.length}</span></h3>${items.map(c=>`<article class="sc-card" draggable="true" data-id="${c.id}"><strong>${esc(c.user_name)}</strong><small>${esc(c.user_email||'')}</small><p class="reason">${esc(crmSummary(c))}</p><div class="meta"><span>${esc(c.priority||'normal')}</span><span>${fmt(c.last_message_at)}</span></div></article>`).join('')||'<div class="sc-empty" style="padding:26px;color:#64748b">Sem atendimentos.</div>'}</section>`}).join('')+'</div>';bindCrmBoard()}
