function initials(n){return String(n||'A').split(/\s+/).slice(0,2).map(x=>x[0]).join('').toUpperCase()}function fmt(d){return d?new Date(String(d).replace(' ','T')).toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'}):''}function fmtDate(d){return d?new Date(String(d).replace(' ','T')).toLocaleDateString('pt-BR',{day:'2-digit',month:'2-digit'}):'-'}
function fmtFull(d){return d?new Date(String(d).replace(' ','T')).toLocaleString('pt-BR',{day:'2-digit',month:'2-digit',year:'2-digit',hour:'2-digit',minute:'2-digit'}):'-'}
function supportStatusLabel(c){if(!c)return 'Central de suporte';if(c.status==='closed')return c.assigned_name?`Concluído · ${c.assigned_name}`:'Concluído';if(c.assigned_name)return `Atribuído a ${c.assigned_name}`;if(c.stage==='agent'||c.status==='open')return 'Com agente IA';return 'Em aberto'}
