function updateSupportHeaderStatus(c){c=c||SC_CONTEXT?.conversation;const head=document.getElementById('scChatHead'),small=document.querySelector('#scChatHead .meta small'),isClosed=!!c&&c.status==='closed',isAi=supportIsAi(c);if(small)small.textContent=supportStatusLabel(c);if(head){head.classList.toggle('ai',isAi);head.classList.toggle('closed',isClosed);head.classList.toggle('open',!!c&&!isClosed&&!isAi)}}
function playSupportSound(){if(!SC.soundEnabled)return;try{const C=window.AudioContext||window.webkitAudioContext;if(!C)return;const ctx=SC.audioCtx||(SC.audioCtx=new C()),now=ctx.currentTime,o=ctx.createOscillator(),g=ctx.createGain();o.type='sine';o.frequency.setValueAtTime(880,now);o.frequency.setValueAtTime(660,now+.12);g.gain.setValueAtTime(.001,now);g.gain.exponentialRampToValueAtTime(.08,now+.025);g.gain.exponentialRampToValueAtTime(.001,now+.22);o.connect(g);g.connect(ctx.destination);o.start(now);o.stop(now+.24)}catch(e){}}
function updateSupportBadge(count){const label=count>99?'99+':String(count),title=count+' aluno(s) aguardando atendimento humano',link=document.querySelector('a.sb-item[href*="suporte_chat.php"]'),tab=document.querySelector('.sc-tab[href*="view=live"]');if(link){let badge=link.querySelector('.sb-support-badge');if(count>0){if(!badge){badge=document.createElement('span');badge.className='sb-support-badge';link.appendChild(badge)}badge.textContent=label;badge.title=title}else badge?.remove()}if(tab){let badge=tab.querySelector('.sc-waiting-badge');if(count>0){if(!badge){badge=document.createElement('span');badge.className='sc-waiting-badge';tab.appendChild(badge)}badge.textContent=label;badge.title=title}else badge?.remove()}}
