if(window.fpsAnalyze)fpsAnalyze.onclick=analyzeSupportFps;
let typingTimer,conversationFilterTimer;scText.oninput=()=>{if(!SC.conversation||typingTimer)return;typingTimer=setTimeout(()=>typingTimer=null,1800);post('typing',{conversation_id:SC.conversation,actor_type:'admin',actor_name:SC.identity.name}).catch(()=>{})};crmSave.onclick=async()=>{if(!SC.conversation)return;await post('update_crm',{conversation_id:SC.conversation,assigned_name:crmAssigned.value,stage:crmStage.value,priority:crmPriority.value,status:crmStatus.value,tags:crmTags.value,notes:crmNotes.value});alert('Atendimento atualizado.');loadConversations()};function queueConversationSearch(){clearTimeout(conversationFilterTimer);conversationFilterTimer=setTimeout(loadConversations,250)}scSearch.oninput=queueConversationSearch;scDateFrom.onchange=loadConversations;scDateTo.onchange=loadConversations;if(window.scAssigneeFilter)scAssigneeFilter.onchange=loadConversations;
openSimulator.onclick=()=>simulator.classList.add('open');closeSimulator.onclick=()=>simulator.classList.remove('open');let searchTimer;studentSearch.oninput=()=>{clearTimeout(searchTimer);searchTimer=setTimeout(async()=>{const q=studentSearch.value.trim();if(q.length<2)return studentResults.innerHTML='';const j=await api('suporte_chat.php?api=students&q='+encodeURIComponent(q));studentResults.innerHTML=j.items.map(x=>`<div class="sc-student" data-id="${x.id}"><b>${esc(x.nome)}</b><br>${esc(x.email)}</div>`).join('');document.querySelectorAll('.sc-student').forEach(x=>x.onclick=async()=>{const j=await post('create_test',{user_id:x.dataset.id});SC.simConversation=j.conversation_id;SC.lastSim=0;simPicker.style.display='none';simText.disabled=false;await refreshSim(true);loadConversations()})},300)};
async function refreshSim(full=false){if(!SC.simConversation)return;const j=await api(`suporte_chat.php?api=messages&conversation_id=${SC.simConversation}&after=${full?0:SC.lastSim}`);if(full)simMessages.innerHTML='';let added=0,notify=false;j.messages.forEach(m=>{SC.lastSim=Math.max(SC.lastSim,+m.id);if(m.id&&simMessages.querySelector(`[data-message-id="${m.id}"]`))return;simMessages.insertAdjacentHTML('beforeend',messageHtml(m,true));added++;if(!full&&m.sender_type!=='student')notify=true});if(added)simMessages.scrollTop=simMessages.scrollHeight;if(notify)playSupportSound();}
let simSending=false,simLastSendKey='';function simPendingHtml(){return`<div class="sc-msg bot" id="simPending"><div class="sign">Agente de suporte</div><span class="sc-dots"><i></i><i></i><i></i></span> digitando...</div>`}simCompose.onsubmit=async e=>{e.preventDefault();if(simSending||!SC.simConversation)return;const file=simFile.files[0],body=simText.value,key=[SC.simConversation,'student',body.trim(),file?file.name+':'+file.size+':'+file.lastModified:''].join('|');if(!body.trim()&&!file)return;if(key===simLastSendKey)return;simSending=true;simLastSendKey=key;simCompose.querySelector('.sc-send').disabled=true;simText.value='';simFile.value='';simMessages.insertAdjacentHTML('beforeend',messageHtml({sender_type:'student',body:body||(file?'Arquivo enviado':''),message_type:'text',created_at:new Date().toISOString().slice(0,19).replace('T',' ')},true)+simPendingHtml());simMessages.scrollTop=simMessages.scrollHeight;try{await post('send',{conversation_id:SC.simConversation,sender_type:'student',body},file);document.getElementById('simPending')?.remove();await refreshSim(true);loadConversations()}catch(err){simLastSendKey='';document.getElementById('simPending')?.remove();alert(err.message)}finally{setTimeout(()=>{if(simLastSendKey===key)simLastSendKey=''},5000);simSending=false;simCompose.querySelector('.sc-send').disabled=false}};simAttach.onclick=()=>{if(!SC.simConversation)return alert('Escolha um aluno primeiro.');simFile.click()};simFile.onchange=()=>{if(simFile.files[0])simCompose.requestSubmit()};let simAudioRecording=null;async function toggleRecording(btn,sender,getConversation,afterSend){const conversationId=getConversation();if(!conversationId)return alert('Escolha um aluno primeiro.');if(simAudioRecording){simAudioRecording.send=true;simAudioRecording.recorder.stop();return}try{const stream=await navigator.mediaDevices.getUserMedia({audio:true}),mime=preferredAudioMime(),recorder=new MediaRecorder(stream,mime?{mimeType:mime}:{}),chunks=[];simAudioRecording={recorder,stream,chunks,send:false,mime};btn.classList.add('recording');recorder.ondataavailable=e=>{if(e.data.size)chunks.push(e.data)};recorder.onstop=async()=>{stream.getTracks().forEach(t=>t.stop());const state=simAudioRecording,shouldSend=state?.send,actual=recorder.mimeType||mime||'audio/webm';btn.classList.remove('recording');simAudioRecording=null;if(!shouldSend||!chunks.length)return;const ext=actual.includes('ogg')?'ogg':'webm',file=new File([new Blob(chunks,{type:actual})],`audio-${Date.now()}.${ext}`,{type:actual}),localUrl=URL.createObjectURL(file);simMessages.insertAdjacentHTML('beforeend',messageHtml({sender_type:'student',message_type:'audio',local_url:localUrl,created_at:new Date().toISOString().slice(0,19).replace('T',' ')},true)+simPendingHtml());simMessages.scrollTop=simMessages.scrollHeight;try{await post('send',{conversation_id:conversationId,sender_type:sender,body:''},file);document.getElementById('simPending')?.remove();URL.revokeObjectURL(localUrl);await refreshSim(true);afterSend&&afterSend()}catch(err){document.getElementById('simPending')?.remove();URL.revokeObjectURL(localUrl);alert('Falha ao enviar áudio: '+err.message)}};recorder.start(250)}catch(err){btn.classList.remove('recording');alert(err.name==='NotAllowedError'?'Permita o microfone no navegador.':err.message)}}simRecord.onclick=()=>toggleRecording(simRecord,'student',()=>SC.simConversation,()=>{refreshSim();loadConversations()});simText.oninput=()=>{if(SC.simConversation)post('typing',{conversation_id:SC.simConversation,actor_type:'student',actor_name:'Aluno'}).catch(()=>{})};
const TYPES={trigger:['Gatilho','#22c55e'],typing:['Digitando','#38bdf8'],message:['Mensagem','#25d366'],support_chat:['Chat central','#06b6d4'],ai:['Primeira interação IA','#a78bfa'],condition:['Condição','#f59e0b'],end:['Encerrar','#ef4444']};let selected=null,drag=null,pending=null;function summary(n){const c=n.config||{};return n.type==='message'||n.type==='ai'||n.type==='support_chat'?(c.text||'Configure a mensagem').slice(0,75):n.type==='typing'?`${c.seconds||2}s de digitação`:n.type==='condition'?`${c.field||'stage'} contém ${c.value||'...'}`:TYPES[n.type][0]}
function renderGraph(){scBoard.innerHTML='';SC.graph.nodes.forEach(n=>{const el=document.createElement('div');el.className='sc-node'+(selected===n.id?' active':'');el.style.cssText=`left:${n.x}px;top:${n.y}px;--nc:${TYPES[n.type][1]}`;el.dataset.id=n.id;el.innerHTML=`<b>${esc(n.config?.label||TYPES[n.type][0])}</b><p>${esc(summary(n))}</p>${n.type!=='end'?'<i class="port"></i>':''}`;el.onclick=e=>{if(e.target.classList.contains('port')){pending=n.id;return}if(pending&&pending!==n.id){SC.graph.edges.push({id:'e'+Date.now(),source:pending,target:n.id,sourceHandle:'default'});pending=null}selected=n.id;renderGraph();renderInspector()};el.onpointerdown=e=>{if(e.target.classList.contains('port'))return;drag={n,x:e.clientX,y:e.clientY,nx:n.x,ny:n.y};el.setPointerCapture(e.pointerId)};el.onpointermove=e=>{if(!drag||drag.n!==n)return;n.x=Math.max(0,drag.nx+e.clientX-drag.x);n.y=Math.max(0,drag.ny+e.clientY-drag.y);el.style.left=n.x+'px';el.style.top=n.y+'px'};el.onpointerup=()=>drag=null;scBoard.appendChild(el)});}
function renderInspector(){const n=SC.graph.nodes.find(x=>x.id===selected);if(!n)return scInspector.innerHTML='Selecione um bloco.';const c=n.config||(n.config={});let h=`<label>Nome do bloco</label><input data-k="label" value="${esc(c.label||TYPES[n.type][0])}">`;if(n.type==='typing')h+=`<label>Segundos</label><input type="number" min="0" max="5" data-k="seconds" value="${c.seconds||2}">`;if(n.type==='message'||n.type==='ai')h+=`<label>Texto</label><textarea data-k="text">${esc(c.text||'')}</textarea><label>Botões (um por linha)</label><textarea data-k="buttonsText">${esc((c.buttons||[]).join('\n'))}</textarea>`;if(n.type==='support_chat')h+=`<label>Mensagem para o aluno</label><textarea data-k="text">${esc(c.text||'')}</textarea><label>Depois de enviar</label><select data-k="handoff"><option value="ia" ${(c.handoff||'ia')==='ia'?'selected':''}>Manter com IA</option><option value="human" ${c.handoff==='human'?'selected':''}>Passar para humano</option></select><p class="text-muted text-xs">A mensagem entra no chat da central, notifica o aluno e atualiza o atendimento.</p>`;if(n.type==='condition')h+=`<label>Campo</label><select data-k="field"><option value="stage">Etapa CRM</option><option value="priority">Prioridade</option><option value="status">Status</option></select><label>Contém</label><input data-k="value" value="${esc(c.value||'')}"><p class="text-muted text-xs">Use conexões condicionais para separar SIM e NÃO.</p>`;h+=n.type!=='trigger'?'<button class="btn btn-danger btn-sm" id="deleteNode">Excluir bloco</button>':'';scInspector.innerHTML=h;scInspector.querySelectorAll('[data-k]').forEach(i=>i.oninput=()=>{c[i.dataset.k]=i.type==='number'?+i.value:i.value;if(i.dataset.k==='buttonsText')c.buttons=i.value.split('\n').filter(Boolean);renderGraph()});const deleteButton=document.getElementById('deleteNode');if(deleteButton)deleteButton.onclick=()=>{SC.graph.nodes=SC.graph.nodes.filter(x=>x.id!==n.id);SC.graph.edges=SC.graph.edges.filter(x=>x.source!==n.id&&x.target!==n.id);selected=null;renderGraph();renderInspector()}}
Object.entries(TYPES).forEach(([type,m])=>{const b=document.createElement('button');b.textContent='● '+m[0];b.style.color=m[1];b.onclick=()=>{if(type==='trigger'&&SC.graph.nodes.some(n=>n.type==='trigger'))return alert('Já existe um gatilho.');const defaultText=type==='ai'?'Olá! Sou o assistente virtual. Como posso ajudar?':(type==='support_chat'?'Oi {primeiro_nome}, vou te atender por aqui na central de suporte.':'');SC.graph.nodes.push({id:type+'_'+Date.now(),type,x:120+SC.graph.nodes.length*30,y:100+SC.graph.nodes.length*25,config:{label:m[0],seconds:2,text:defaultText,handoff:'ia',buttons:[]}});renderGraph()};scPalette.appendChild(b)});renderGraph();renderInspector();flowSave.onclick=async()=>{const j=await post('save_flow',{flow_id:SC.flowId,name:flowName.value,status:flowStatus.value,graph_json:JSON.stringify(SC.graph)});SC.flowId=j.flow_id;alert('Automação salva. Ela atua somente no simulador.')};if(window.agentSave)agentSave.onclick=async()=>{await post('save_agent',{enabled:agentEnabled.checked?1:'',basic_enabled:agentBasic.checked?1:'',sales_enabled:agentSales.checked?1:'',technical_enabled:agentTechnical.checked?1:'',reschedule_enabled:agentReschedule.checked?1:'',certificate_enabled:agentCertificate.checked?1:'',group_enabled:agentGroup.checked?1:'',max_tokens:agentMaxTokens.value,pause_seconds:agentPauseSeconds.value,auto_close_minutes:window.agentAutoCloseMinutes?agentAutoCloseMinutes.value:30,closing_message:window.agentClosingMessage?agentClosingMessage.value:'',human_idle_close_hours:window.agentHumanIdleHours?agentHumanIdleHours.value:24,human_idle_message:window.agentHumanIdleMessage?agentHumanIdleMessage.value:'',followup_variations:window.agentFollowups?agentFollowups.value:'',group_link_template:agentGroupTemplate.value,prompt_basic:agentPromptBasic.value,prompt_sales:agentPromptSales.value,prompt_technical:agentPromptTechnical.value,prompt_reschedule:agentPromptReschedule.value,prompt_certificate:agentPromptCertificate.value,prompt_group:agentPromptGroup.value,handoff_message:agentHandoff.value,variable_map_json:agentVarsJson(),crm_stages_json:crmStagesJson.value});alert('Agente salvo.')};settingsSave.onclick=async()=>{await post('save_settings',{button_mode:setButtonMode.value,display_name:setDisplayName.value,welcome:setWelcome.value,offline:setOffline.value,font_scale:setFontScale.value,sound_enabled:setSoundEnabled.checked?1:''},setAvatar.files[0]||null);SC.soundEnabled=setSoundEnabled.checked;document.querySelector('.sc-shell')?.style.setProperty('--support-font-scale',Math.max(.85,Math.min(1.35,parseFloat(String(setFontScale.value).replace(',','.'))||1.08)).toFixed(2));document.querySelector('.sc-simulator')?.style.setProperty('--support-font-scale',Math.max(.85,Math.min(1.35,parseFloat(String(setFontScale.value).replace(',','.'))||1.08)).toFixed(2));alert('Configurações salvas.')};
if(SC.conversation){setSupportView('live');selectConversation(SC.conversation)}else loadConversations();setInterval(()=>{refreshAdmin();refreshSim();loadConversations()},3000);
